const express = require('express');
const mongoose = require('mongoose');

const app = express();
app.use(express.json());

// Connect to MongoDB
mongoose.connect('mongodb://localhost:27017/admin_dashboard', {
  useNewUrlParser: true,
  useUnifiedTopology: true,
});

// Define a sample schema and model
const UserSchema = new mongoose.Schema({
  name: String,
  age: Number,
  password: String,
  createdAt: Date,
});
const User = mongoose.model('User', UserSchema);

// Flexible MongoDB query builder function
function queryBuilder(filter, projection, sort) {
  return async (req, res) => {
    try {
      const query = User.find(filter);
      if (projection) {
        query.select(projection);
      }
      if (sort) {
        query.sort(sort);
      }
      const results = await query.exec();
      res.json(results);
    } catch (error) {
      res.status(500).json({ error: 'Internal Server Error' });
    }
  };
}

// Example usage
const getUsers = queryBuilder(
  { age: { $gt: 18 }, name: { $regex: '^J' } },
  { password: 0 },
  { createdAt: -1 }
);

app.get('/users', getUsers);

app.listen(3000, () => {
  console.log('Server is running on port 3000');
});